import{_ as a,o as t,c as p,j as r,a as b,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"翅振","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/6.套装/翅振.md","filePath":"4.资源分区/7.物品与装备/6.套装/翅振.md"}'),s={name:"4.资源分区/7.物品与装备/6.套装/翅振.md"};function o(d,e,l,i,_,c){return t(),p("div",null,[...e[0]||(e[0]=[r("h1",{id:"翅振",tabindex:"-1"},[b("翅振 "),r("a",{class:"header-anchor",href:"#翅振","aria-label":'Permalink to "翅振"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：新世短歌033")])])],-1),n('<h1 id="翅振-1" tabindex="-1">翅振 <a class="header-anchor" href="#翅振-1" aria-label="Permalink to &quot;翅振&quot;">​</a></h1><p>翅振</p><p>只要有了小精灵们的祝福，一切争端都会平息下来的。<br> ——————————<br> 武器：<br> 价格：D+500<br> 这是一把青绿色棁，武器上闪耀着和精灵们身上相同的，苍白的光。</p><p>伤害类型：物理-钝击<br> 武器模版：短棍<br> 武器伤害：5L<br> 【高速2】【格挡1】</p><p>【贪食】：说到底，这些精灵不过是一群爱吃肉的怪物罢了，所谓的“呵护”也仅仅是为了保持食物的新鲜。<br> 当你使用这把武器时，这把武器的会盯住你面前的生物，随后如同进食一般将它们吞噬，你获得【吸血1】</p><p>——————————<br> 护甲：<br> 价格：D+500<br> 这是一件青绿色的护甲，这件护甲并不像精灵的羽翼那样轻薄，而要沉重许多。</p><p>盔甲防御：5/5<br> 盔甲类型：轻甲</p><p>【精灵的呵护】：精灵会保护职员们。在她们的悉心照料下，一切都会变得安宁祥和。<br> 当穿上这套护甲时，你自然获得了小精灵的祝福，你获得遮蔽防御2以及【快速医疗1】（医疗点24）</p><p>——————————<br> 饰品：<br> 价格：D+500<br> 这是一双青色的散发苍白的光芒的手套，戴上它，你会感觉到小精灵就在自己的身旁。占据你的手套位。</p><p>【猎食】：他的内脏和眼球遭到不明生物啃食，受损严重。此外，我们察觉到精灵们的嘴角沾有某人的血肉。<br> 戴上这对手套时，你也会向那些小精灵一般，对猎物（食物）有着迫不及待的欲望<br> 现在，你的先攻提高4点，在你冲锋时有效距离取最大值计算，且冲锋时你将获得【高速5】</p><p>——————————<br> 绿色鞘翅<br> D+500<br> 占据斗篷位<br> “如果刚刚你们还呆在雨里……我亲手把你们柔滑的皮扒下来还得费点功夫。”<br> “但谢天谢地……我现在不需要麻烦了。”</p><p>以一个迅捷动作消耗1点意志力启用，你俯身做出冲锋的架势，随后直到你的下轮行动结束为止，你的先攻上升10点，并且在下次攻击命中后，获得一层【呼吸】。</p><p>【呼吸】<br> 拥有该词条的单位在进行一次以生理属性作为关键属性的攻击前须投掷一个D10的自然骰，若出目不大于呼吸层数，则令这次攻击造成的伤害增加一半并消耗一层呼吸层数。<br> 一个单位的具有呼吸层数上限为10层。<br> 呼吸层数会在战斗结束时清空。</p><p>——————————<br> 套装效果：（4/4)<br> 温柔呵护朕的精灵……是最为珍贵的存在……</p><p>【饥饿狂暴】：<br> 当你的完好生命被严重伤害填满至少一半时：<br> 你冲锋的移动行为结束后，即使对方离开了攻击范围，也可以按照脱离攻击范围一般进行冲锋攻击<br> 当你没有任何完好生命时，此套装提供的吸血提升4点</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',17)])])}const m=a(s,[["render",o]]);export{f as __pageData,m as default};
